1. Prefect Substring Solution.

int solution(string& s, int k){
int prev=0, l=0, h=k-1, res=0;
while(h<s.length()){
int m=check(l,h,s[l],s);
if(m==h+1){
res+=(prev+1);
prev++;
l=m;
h=l+k-1;
}
else{
prev=0;
l=m;
h=l+k-1;
}
}
return res;
}

int check(int i, int j, char c, string& s){
int a=i;
for(a; a<=min(j,s.length()-1); a++){
if(s[a]!=c){return a;}
}
return a;
}
